outputText:
{
  "project_name": "智能日历",
  "version": "V1.0",
  "user_goals": [
    "通过CLI（命令行界面）实现日程的快速记录与查询",
    "解决传统图形界面日历操作路径长、打断工作流的问题"
  ],
  "core_scenarios": [
    {
      "scenario_name": "快速记录日程",
      "description": "用户在终端工作环境中，直接输入自然语言需求（如'明天下午3点开会'），系统自动解析并完成日程记录"
    },
    {
      "scenario_name": "查询日程",
      "description": "用户在终端通过自然语言提问（如'我今天有什么安排'），系统快速返回对应的日程信息"
    }
  ],
  "core_features": [
    {
      "feature_id": "F001",
      "feature_name": "自然语言日程录入",
      "description": "接收用户输入的自然语言，提取时间、事件等关键要素并生成日程记录"
    },
    {
      "feature_id": "F002",
      "feature_name": "自然语言日程查询",
      "description": "接收用户的自然语言提问，解析时间范围，检索并展示匹配的日程列表"
    },
    {
      "feature_id": "F003",
      "feature_name": "本地数据存储",
      "description": "将解析后的日程数据持久化存储在本地，保障数据隐私与离线可用性"
    }
  ],
  "constraints": [
    "交互形式：必须基于CLI（命令行界面）",
    "数据存储：必须支持本地存储",
    "其他约束：导出格式、安全机制、发布时间等暂未明确"
  ],
  "pending_issues": [
    "需明确目标用户的具体画像与高频使用场景细节",
    "需明确自然语言解析的容错率与边界情况处理机制",
    "需明确本地存储的具体技术方案（如SQLite、JSON文件等）",
    "需确认是否包含日程提醒/通知功能",
    "需确认是否需要数据导出功能及支持的格式",
    "需补充会议纪要、需求文档或竞品材料以完善上下文"
  ]
}

